use EmadeDevcreate table EmadeActivity ( player_id     int     , device_id     int     , event_date    date    , games_played  int ); insert into EmadeActivity  values (1,2,'2016-03-01',5 ) ,(1,2,'2016-03-02',6 ) ,(2,3,'2017-06-25',1 ) ,(3,1,'2016-03-02',0 ) ,(3,4,'2018-07-03',5 ); Select * From EmadeActivity--questions:--Game Play Analysis --q1: Write an SQL query that reports the first login date for each playerSELECT player_id, MIN(event_date) AS first_login FROM EmadeActivity GROUP BY player_id;--ALTselect player_id, event_date as "first login date"from	(select *, row_number() over(partition by player_id order by event_date) rnk	from EmadeActivity) awhere rnk = 1;--q2: Write a SQL query that reports the device that is first logged in for each playerSELECT player_id, device_idFROM (    SELECT player_id, device_id,           ROW_NUMBER() OVER(PARTITION BY player_id ORDER BY event_date) as rn    FROM EmadeActivity) tWHERE rn = 1;--q3: Write an SQL query that reports for each player and date, how many games played so far by the player. --That is, the total number of games played by the player until that date.SELECT player_id, event_date,        SUM(games_played) OVER (PARTITION BY player_id ORDER BY event_date) AS games_played_so_far FROM EmadeActivity;--q4: Write an SQL query that reports the fraction of players that logged in again -- on the day after the day they first logged in, rounded to 2 decimal placesWITH FirstLogin AS (    SELECT player_id, MIN(event_date) AS first_date    FROM EmadeActivity    GROUP BY player_id)SELECT ROUND(    COUNT(a.player_id) * 1.0 / (SELECT COUNT(DISTINCT player_id) FROM EmadeActivity),     2) AS fractionFROM FirstLogin fJOIN EmadeActivity a   ON f.player_id = a.player_id   AND a.event_date = DATEADD(day, 1, f.first_date);